+ (UIViewController *)getUIApplicationCurrentViewController {
    UIViewController *currentVC = [WBAppManager getUIApplicationRootViewController];

    BOOL runLoopFind = YES;
    while (runLoopFind && currentVC) {
        if (currentVC.presentedViewController) {
            currentVC = currentVC.presentedViewController;
        }
        else if ([currentVC isKindOfClass:[UINavigationController class]]) {
            currentVC = ((UINavigationController *)currentVC).visibleViewController;
        } else if ([currentVC isKindOfClass:[UITabBarController class]]) {
            currentVC = ((UITabBarController *)currentVC).selectedViewController;
        }
        else {
            runLoopFind = NO;
        }
    }
    return currentVC;
}


