- (void)loadLocalAppsWithCallback:(VAppsDataLoadCallback)callback {
    NSString *plistPath = [NSBundle.mainBundle pathForResource:@"WBVappScheme.plist" ofType:nil];
    NSArray *appsInPlist = [NSArray modelArrayWithClass:WBVAppBaseHttpModel.class json:[NSArray arrayWithContentsOfFile:plistPath]];
    NSArray *vapps = [self parseVAppHttpModelList:appsInPlist];
    self.localApps = [NSMutableArray array];
    for (WBVAppModel *app in vapps) {
        if ([UIApplication.sharedApplication canOpenURL:[NSURL URLWithString:app.scheme]]) {
            //            NSLog(@"can open %@", app.name);
            [self.localApps addObject:app];
        }
    }
    if (self.localApps.count > 0) {
        if (callback) callback(self.localApps, TRUE);
    } else {
        if (callback) callback(self.localApps, FALSE);
    }
}

